import{_ as o,o as t,c as a,ai as l}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"grammY","description":"","frontmatter":{"summary":"Telegram Bot API integration via grammY with setup notes","read_when":["Working on Telegram or grammY pathways"],"title":"grammY"},"headers":[],"relativePath":"channels/grammy.md","filePath":"channels/grammy.md","lastUpdated":1771906665000}'),r={name:"channels/grammy.md"};function n(s,e,i,d,c,m){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="grammy-integration-telegram-bot-api" tabindex="-1"><a class="header-anchor" href="#grammy-integration-telegram-bot-api">#</a> grammY Integration (Telegram Bot API)</h1><h1 id="why-grammy" tabindex="-1"><a class="header-anchor" href="#why-grammy">#</a> Why grammY</h1><ul><li>TS-first Bot API client with built-in long-poll + webhook helpers, middleware, error handling, rate limiter.</li><li>Cleaner media helpers than hand-rolling fetch + FormData; supports all Bot API methods.</li><li>Extensible: proxy support via custom fetch, session middleware (optional), type-safe context.</li></ul><h1 id="what-we-shipped" tabindex="-1"><a class="header-anchor" href="#what-we-shipped">#</a> What we shipped</h1><ul><li><strong>Single client path:</strong> fetch-based implementation removed; grammY is now the sole Telegram client (send + gateway) with the grammY throttler enabled by default.</li><li><strong>Gateway:</strong> <code>monitorTelegramProvider</code> builds a grammY <code>Bot</code>, wires mention/allowlist gating, media download via <code>getFile</code>/<code>download</code>, and delivers replies with <code>sendMessage/sendPhoto/sendVideo/sendAudio/sendDocument</code>. Supports long-poll or webhook via <code>webhookCallback</code>.</li><li><strong>Proxy:</strong> optional <code>channels.telegram.proxy</code> uses <code>undici.ProxyAgent</code> through grammY’s <code>client.baseFetch</code>.</li><li><strong>Webhook support:</strong> <code>webhook-set.ts</code> wraps <code>setWebhook/deleteWebhook</code>; <code>webhook.ts</code> hosts the callback with health + graceful shutdown. Gateway enables webhook mode when <code>channels.telegram.webhookUrl</code> + <code>channels.telegram.webhookSecret</code> are set (otherwise it long-polls).</li><li><strong>Sessions:</strong> direct chats collapse into the agent main session (<code>agent:&lt;agentId&gt;:&lt;mainKey&gt;</code>); groups use <code>agent:&lt;agentId&gt;:telegram:group:&lt;chatId&gt;</code>; replies route back to the same channel.</li><li><strong>Config knobs:</strong> <code>channels.telegram.botToken</code>, <code>channels.telegram.dmPolicy</code>, <code>channels.telegram.groups</code> (allowlist + mention defaults), <code>channels.telegram.allowFrom</code>, <code>channels.telegram.groupAllowFrom</code>, <code>channels.telegram.groupPolicy</code>, <code>channels.telegram.mediaMaxMb</code>, <code>channels.telegram.linkPreview</code>, <code>channels.telegram.proxy</code>, <code>channels.telegram.webhookSecret</code>, <code>channels.telegram.webhookUrl</code>.</li><li><strong>Draft streaming:</strong> optional <code>channels.telegram.streamMode</code> uses <code>sendMessageDraft</code> in private topic chats (Bot API 9.3+). This is separate from channel block streaming.</li><li><strong>Tests:</strong> grammy mocks cover DM + group mention gating and outbound send; more media/webhook fixtures still welcome.</li></ul><p>Open questions</p><ul><li>Optional grammY plugins (throttler) if we hit Bot API 429s.</li><li>Add more structured media tests (stickers, voice notes).</li><li>Make webhook listen port configurable (currently fixed to 8787 unless wired through the gateway).</li></ul>',7)])])}const p=o(r,[["render",n]]);export{h as __pageData,p as default};
